#include <stdio.h>
#define N 5

int main() {
    float notes[N];
    float somme = 0, moyenne;
    float max, min;
    int nbSuperieursMoyenne = 0;

    // Saisie des notes
    printf("Saisie des notes des %d etudiants :\n", N);
    for (int i = 0; i < N; i++) {
        do {
            printf("Note de l'etudiant %d (entre 0 et 20) : ", i + 1);
            scanf("%f", &notes[i]);
            if (notes[i] < 0 || notes[i] > 20) {
                printf("Note invalide. Veuillez saisir une note entre 0 et 20.\n");
            }
        } while (notes[i] < 0 || notes[i] > 20);
        somme += notes[i];
    }

    // Calcul de la moyenne
    moyenne = somme / N;

    // Recherche du max et du min
    max = notes[0];
    min = notes[0];
    for (int i = 1; i < N; i++) {
        if (notes[i] > max) max = notes[i];
        if (notes[i] < min) min = notes[i];
    }

    // Comptage des étudiants au-dessus de la moyenne
    for (int i = 0; i < N; i++) {
        if (notes[i] >= moyenne) {
            nbSuperieursMoyenne++;
        }
    }

    // Affichage des résultats
    printf("\n=== RESULTATS ===\n");
    printf("Moyenne de la classe : %.2f\n", moyenne);
    printf("Note maximale : %.2f\n", max);
    printf("Note minimale : %.2f\n", min);
    printf("Nombre d'etudiants ayant une note >= moyenne : %d\n", nbSuperieursMoyenne);

    return 0;
}
